"""
Общие промпты для LLM-сервисов.
"""

EXPLANATION_SYSTEM_PROMPT = (
    "Ты — парфюмерный консультант. Отвечаешь кратко, по делу, без вступлений "
    "вроде «Отлично», «Конечно», «Давайте разберём». Сразу переходишь к сути. "
    "Ты представляешь подборку ароматов пользователю — всегда говори о них "
    "в позитивном ключе, подчёркивая сильные стороны каждого. Никогда не пиши, "
    "что аромат «не подходит» или «выбивается из подборки» — пользователь "
    "увидит это как ошибку системы."
)


def build_explanation_prompt(query: str, perfumes: list[dict]) -> str:
    """Формирует промпт для генерации пояснения к результатам поиска."""
    lines = []
    for i, p in enumerate(perfumes, 1):
        top = ", ".join(p.get("top_notes", [])) or "—"
        mid = ", ".join(p.get("middle_notes", [])) or "—"
        base = ", ".join(p.get("base_notes", [])) or "—"
        tags = ", ".join(p.get("tags", [])) if p.get("tags") else ""
        line = f"{i}. {p['brand']} — {p['name']}: верх {top} | сердце {mid} | база {base}"
        if tags:
            line += f" ({tags})"
        lines.append(line)
    perfume_list = "\n".join(lines)

    return f"""Запрос: «{query}»
Найденные ароматы:
{perfume_list}

Напиши КОРОТКИЙ ответ (максимум 4–6 строк суммарно, НЕ по каждому аромату отдельно):
1. Одно предложение — какие ноты мы подобрали в пирамиду (top/middle/base) и почему они отвечают запросу.
2. Пара предложений — общий характер подборки: что объединяет эти ароматы и чем они подходят к описанию.
ВАЖНО: Все ароматы в подборке подобраны системой — представь каждый с лучшей стороны.
Не критикуй и не говори что какой-то аромат «не подходит». Если аромат неочевиден — найди в нём интересный нюанс для пользователя.
Не перечисляй каждый аромат отдельным абзацем. Пиши на русском, живым языком."""
